pure fn day_kind(d: Number) -> Text {
    return match d {
        0 => "weekend",
        6 => "weekend",
        _ => "weekday"
    }
}
entry main(x: Text) { return day_kind(0) }

pure fn beats(choice: Text) -> Text {
    return match choice {
        "rock" => "scissors",
        "paper" => "rock",
        "scissors" => "paper",
        _ => "unknown"
    }
}
entry main(x: Text) { return beats("paper") }

pure fn primary_or_other(color: Text) -> Text {
    return match color {
        "red" => "primary",
        "blue" => "primary",
        "yellow" => "primary",
        _ => "other"
    }
}
entry main(x: Text) { return primary_or_other("green") }

intent classify_sentiment(text: Text) -> Text {
    goal: positive_or_negative
}
entry main(x: Text) {
    return match classify_sentiment("I love this") {
        "positive" with confidence > 0.8 => "strongly positive",
        "negative" with confidence > 0.8 => "strongly negative",
        _ with confidence > 0.5 => "somewhat uncertain",
        _ => "too uncertain"
    }
}

intent urgency_of(text: Text) -> Text {
    goal: urgent_or_calm
}
entry main(x: Text) {
    return match urgency_of("meeting at 3pm tomorrow") {
        "urgent" with confidence > 0.85 => "CRITICAL",
        "calm" with confidence > 0.85 => "RELAXED",
        _ => "REVIEW_MANUALLY"
    }
}

pure fn direct_parse(text: Text) -> Number { return to_number(trim(text)) }
pure fn scan_tokens(text: Text) -> Number {
    for t in split(text, " ") {
        n = to_number(t)
        if is_ok(n) { return n }
    }
    return error("no number")
}
intent infer_number(text: Text) -> Text { goal: the single number in the text }
entry main(x: Text) {
    return attempt {
        try direct_parse(x)
        try scan_tokens(x)
        try infer_number(x)
    }
}

pure fn table_lookup(code: Text) -> Text {
    if code == "KR" { return "South Korea" }
    if code == "US" { return "United States" }
    if code == "JP" { return "Japan" }
    return error("unknown code")
}
intent name_from_code(code: Text) -> Text {
    goal: the country name matching a two-letter code
}
entry main(x: Text) {
    return attempt {
        try table_lookup("KR")
        try name_from_code("KR")
    }
}

pure fn cheap(x: Number) -> Number { return x + 1 }
pure fn expensive(x: Number) -> Number { return x * 10 }
entry main(xs: Text) {
    return attempt {
        try cheap(5)
        try expensive(5)
    }
}

pure fn safe_div(a: Number, b: Number) -> Number {
    if b == 0 { return error("divide by zero") }
    return ok(a / b)
}
entry main(x: Text) {
    r = safe_div(10, 2)
    if is_ok(r) { return to_text(unwrap(r)) }
    return unwrap_error(r)
}

pure fn safe_div(a: Number, b: Number) -> Number {
    if b == 0 { return error("divide by zero") }
    return ok(a / b)
}
entry main(x: Text) {
    r = safe_div(10, 0)
    if is_ok(r) { return to_text(unwrap(r)) }
    return unwrap_error(r)
}

pure fn parse_one(s: Text) -> Number {
    n = to_number(trim(s))
    if is_error(n) { return error("bad number") }
    return ok(n)
}
pure fn count_good(raw: Text) -> Number {
    good = 0
    for s in split(raw, ",") {
        if is_ok(parse_one(s)) { good = good + 1 }
    }
    return good
}
entry main(x: Text) { return count_good("3,7,xx,12,abc,2") }

import classify from "stdlib/language"
entry main(text: Text) {
    return classify(text, "positive_negative_or_neutral")
}

intent classify_tone(text: Text) -> Text {
    goal: 문장의 톤을 한국어로 분류
}
pure fn char_count(s: Text) -> Number { return length(s) }
entry main(text: Text) {
    return join([to_text(char_count(text)), "자, ", classify_tone(text)], "")
}

intent summarize_ko(text: Text) -> Text {
    goal: 문장을 한국어로 한 문장 요약
}
pure fn char_count(s: Text) -> Number { return length(s) }
entry main(text: Text) {
    s = summarize_ko(text)
    return join([s, " (", to_text(char_count(s)), "자)"], "")
}

pure fn word_count(s: Text) -> Number {
    return length(split(trim(s), " "))
}
entry main(text: Text) {
    return join([to_text(word_count(text)), "단어"], "")
}

pure fn is_primary(color: Text) -> Text {
    primaries = ["red", "blue", "yellow"]
    if color in primaries { return "primary" }
    return "other"
}
entry main(x: Text) { return is_primary("red") }

pure fn keep_nonstops(words: Text) -> Text {
    stops = ["a", "the", "is", "in", "on"]
    out = []
    for w in words {
        if lower(w) not in stops { out = append(out, w) }
    }
    return out
}
entry main(x: Text) { return join(keep_nonstops(["The","cat","is","on","the","mat"]), " ") }

pure fn square(n: Number) -> Number { return n * n }
pure fn sum_of_squares(n: Number) -> Number {
    total = 0
    for i in range(1, n + 1) { total = total + square(i) }
    return total
}
entry main(x: Text) { return sum_of_squares(5) }

pure fn len_eq(w: Text, k: Number) -> Boolean { return length(w) == k }
pure fn count_k_letter(text: Text, k: Number) -> Number {
    total = 0
    for w in split(trim(text), " ") {
        if len_eq(w, k) { total = total + 1 }
    }
    return total
}
entry main(x: Text) { return count_k_letter("the cat sat on the mat", 3) }

intent classify_temp(summary: Text) -> Text {
    goal: cold or mild or hot
}
pure fn f_to_c(f: Number) -> Number { return (f - 32) * 5 / 9 }
entry main(x: Text) {
    c = f_to_c(95)
    summary = join(["temperature ", to_text(c), "C"], "")
    return join([summary, " - ", classify_temp(summary)], "")
}

intent describe_length(summary: Text) -> Text { goal: short or long }
pure fn word_count(s: Text) -> Number {
    return length(split(trim(s), " "))
}
entry main(x: Text) {
    text = "this is a tiny sentence"
    summary = join([to_text(word_count(text)), " words"], "")
    return join([summary, " - ", describe_length(summary)], "")
}

intent even_or_odd(summary: Text) -> Text { goal: even or odd }
pure fn digit_sum(n: Number) -> Number {
    total = 0
    cur = n
    for i in range(0, 20) {
        if cur == 0 { return total }
        total = total + cur % 10
        cur = (cur - cur % 10) / 10
    }
    return total
}
entry main(x: Text) {
    s = digit_sum(127)
    summary = join(["digit sum ", to_text(s)], "")
    return join([summary, " - ", even_or_odd(summary)], "")
}

pure fn count_eq(items: Number, target: Number) -> Number {
    total = 0
    for it in items { if it == target { total = total + 1 } }
    return total
}
entry main(x: Text) { return count_eq([1,2,3,2,4,2,5], 2) }

pure fn gcd(a: Number, b: Number) -> Number {
    if b == 0 { return a }
    return gcd(b, a % b)
}
entry main(x: Text) { return gcd(48, 18) }

pure fn is_prime(n: Number) -> Boolean {
    if n < 2 { return false }
    for d in range(2, n) {
        if d * d > n { return true }
        if n % d == 0 { return false }
    }
    return true
}
entry main(x: Text) { if is_prime(29) { return "yes" } return "no" }
